import Post from "./DATA/Post";

export function getNews(arr) {

    let openReq = indexedDB.open("Post_User_DB", 2)
    let db;
    let transaction;

    openReq.onupgradeneeded = function (e) {
        db = e.target.result;
        if (!db.objectStoreNames.contains("post-user")) {
            db.createObjectStore("post-user", { keyPath: "id" })
        }
        if (!db.objectStoreNames.contains("post-user-likes")) {
            db.createObjectStore("post-user-likes", { keyPath: "id" })
        }
    }

    openReq.onsuccess = function (e) {
        console.log("Success! - getNews");
        db = e.target.result;

        transaction = db.transaction(["post-user"], "readwrite");
        const store = transaction.objectStore("post-user");

        store.add(arr).onsuccess = e => console.log(e);
    }

    openReq.onerror = function (e) {
        console.log("Error - readDataBase");
        // console.dir(e);
    }
}
export function addNews(arrOne) {

    let openReq = indexedDB.open("Post_User_DB", 2)
    let db;
    let transaction;

    openReq.onupgradeneeded = function (e) {
        db = e.target.result;
        if (!db.objectStoreNames.contains("post-user")) {
            db.createObjectStore("post-user", { keyPath: "id" })
        }
        if (!db.objectStoreNames.contains("post-user-likes")) {
            db.createObjectStore("post-user-likes", { keyPath: "id" })
        }
    }

    openReq.onsuccess = function (e) {
        console.log("Success! - addNews");
        db = e.target.result;

        transaction = db.transaction(["post-user"], "readonly");
        const store = transaction.objectStore("post-user");

        store.openCursor().onsuccess = e => {
            const result = e.target.result;
            if (result) {
                let lenOne = `num${Object.keys(arrOne).length}`
                arrOne[lenOne] = result.value
                result.continue()
            }
        }
    }
    openReq.onerror = function (e) {
        console.log("Error - addNews");
    }
}
export function deleteNews(id, word) {

    let openReq = indexedDB.open("Post_User_DB", 2)
    let db;
    let transaction;

    openReq.onupgradeneeded = function (e) {
        db = e.target.result;
        if (!db.objectStoreNames.contains("post-user")) {
            db.createObjectStore("post-user", { keyPath: "id" })
        }
        if (!db.objectStoreNames.contains("post-user-likes")) {
            db.createObjectStore("post-user-likes", { keyPath: "id" })
        }
    }

    openReq.onsuccess = function (e) {
        console.log("Success! - deleteNews");
        db = e.target.result;
        // console.log(id);
        transaction = db.transaction(["post-user"], "readwrite");
        const store = transaction.objectStore("post-user");
        if (word === "user-post") {
            store.delete(id)
        } else {
            store.delete(id)
        }
       
        

    }
    openReq.onerror = function (e) {
        console.log("Error - addNews");
    }
}
export function addLikes(arr) {

    let openReq = indexedDB.open("Post_User_DB", 2)

    openReq.onupgradeneeded = function (e) {
        let db = e.target.result;
        if (!db.objectStoreNames.contains("post-user")) {
            db.createObjectStore("post-user", { keyPath: "id" })
        }
        if (!db.objectStoreNames.contains("post-user-likes")) {
            db.createObjectStore("post-user-likes", { keyPath: "id" })
        }
    }
    openReq.onsuccess = function (e) {
        console.log("Success! - Likes");
        let db = e.target.result;

        let transaction = db.transaction(["post-user-likes"], "readwrite");
        const store = transaction.objectStore("post-user-likes");

        store.add(arr).onsuccess = e => console.log("OK!");
    }

    openReq.onerror = function (e) {
        console.log("Error - addLikes");
    }
}
export function deleteLikes(id) {

    let openReq = indexedDB.open("Post_User_DB", 2)

    openReq.onupgradeneeded = function (e) {
        let db = e.target.result;
        if (!db.objectStoreNames.contains("post-user")) {
            db.createObjectStore("post-user", { keyPath: "id" })
        }
        if (!db.objectStoreNames.contains("post-user-likes")) {
            db.createObjectStore("post-user-likes", { keyPath: "id" })
        }
    }
    openReq.onsuccess = function (e) {
        console.log("Success! - Likes");
        let db = e.target.result;

        let transaction = db.transaction(["post-user-likes"], "readwrite");
        const store = transaction.objectStore("post-user-likes");

        store.delete(id)
    }

    openReq.onerror = function (e) {
        console.log("Error - deleteLikes");
    }
}
export function getLikes(arrOne) {

    let openReq = indexedDB.open("Post_User_DB", 2)

    openReq.onupgradeneeded = function (e) {
        let db = e.target.result;
        if (!db.objectStoreNames.contains("post-user")) {
            db.createObjectStore("post-user", { autoIncrement: true })
        }
        if (!db.objectStoreNames.contains("post-user-likes")) {
            db.createObjectStore("post-user-likes", { autoIncrement: true })
        }
    }

    openReq.onsuccess = function (e) {
        console.log("Success! - getLikes");
        let db = e.target.result;

        let transaction = db.transaction(["post-user-likes"], "readwrite");
        const store = transaction.objectStore("post-user-likes");

        store.openCursor().onsuccess = e => {
            const result = e.target.result;
            if (result) {
                let lenOne = `num${Object.keys(arrOne).length}`
                arrOne[lenOne] = result.value

                // console.log(Object.keys(arrOne).length);
                // console.log(arrOne);
                // let lenTwo = `num${Object.keys(arrTwo).length}`
                // arrTwo[lenTwo] = result.value

                result.continue()
            }
        }
    }
    openReq.onerror = function (e) {
        console.log("Error - getLikes");
        // console.dir(e);
    }
}
export function checkLikes(id, arr) {

    let openReq = indexedDB.open("Post_User_DB", 2)

    openReq.onupgradeneeded = function (e) {
        let db = e.target.result;
        if (!db.objectStoreNames.contains("post-user")) {
            db.createObjectStore("post-user", { autoIncrement: true })
        }
        if (!db.objectStoreNames.contains("post-user-likes")) {
            db.createObjectStore("post-user-likes", { autoIncrement: true })
        }
    }

    openReq.onsuccess = function (e) {
        console.log("Success! - getLikes");
        let db = e.target.result;

        let transaction = db.transaction(["post-user-likes"], "readwrite");
        const store = transaction.objectStore("post-user-likes");

        store.openCursor().onsuccess = e => {
            const result = e.target.result;
            if (result) {
               
                if (id === result.key) {
                    arr = true
                } else {
                    arr = false
                }
                // console.log(Object.keys(arrOne).length);
                // console.log(arrOne);
                // let lenTwo = `num${Object.keys(arrTwo).length}`
                // arrTwo[lenTwo] = result.value

                result.continue()
            }
        }
    }
    openReq.onerror = function (e) {
        console.log("Error - getLikes");
        // console.dir(e);
    }
}
